{
  "type": "DRAG_FILL",
  "lessonText": "Match the ingredients to their uses in Burmese curries.",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks with the correct ingredients.",
        "codeTemplate": "The key ingredient for a rich curry is ____, while ____ adds flavor and depth.",
        "options": ["coconut milk", "turmeric", "lemongrass", "fish sauce"],
        "correctAnswer": "coconut milk, fish sauce",
        "explanation": "Coconut milk provides creaminess, and fish sauce enhances the umami flavor."
      },
      {
        "instruction": "Identify the spices used in Burmese curries.",
        "codeTemplate": "A common spice in Burmese cooking is ____, and ____ is used for heat.",
        "options": ["coriander", "chili powder", "cumin", "ginger"],
        "correctAnswer": "coriander, chili powder",
        "explanation": "Coriander adds a citrusy note, while chili powder brings spiciness."
      },
      {
        "instruction": "Complete the ingredient list for a traditional curry.",
        "codeTemplate": "For a traditional curry, you need ____, along with ____ for aroma.",
        "options": ["onions", "garlic", "bay leaves", "curry leaves"],
        "correctAnswer": "onions, garlic",
        "explanation": "Onions provide sweetness, and garlic adds a robust aroma."
      },
      {
        "instruction": "Match the vegetable to its role in curries.",
        "codeTemplate": "To add texture, use ____, and for color, include ____.",
        "options": ["potatoes", "spinach", "carrots", "bell peppers"],
        "correctAnswer": "potatoes, bell peppers",
        "explanation": "Potatoes give a hearty texture, while bell peppers add vibrant color."
      }
    ]
  }
}
